Install:
npm create svelte@latest my-app

Usage:
npm create svelte@latest my-app

Asset:
<script>
  let count = 0;

  // Reactive statement - automatically re-runs when count changes
  $: doubled = count * 2;
  $: console.log(`Count is now ${count}`);

  function increment() {
    count += 1;
  }
</script>

<div>
  <button on:click={increment}>Count: {count}</button>
  <p>Doubled: {doubled}</p>
</div>
